var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>안내드립니다. 현재 사옥에 무장 괴한들이 침입한 상태입니다.</color>","JPN":"<color=#ffd34c>ご案内いたします。ただいま、社内に武装した不審者が進入している状況です。</color>","ENG":"<color=#ffd34c>Alert. Armed intruders have been detected.</color>","TWN":"<color=#ffd34c>警告，目前有武裝分子入侵公司。</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>사무원 분들은 비상 통로를 통해 대피해 주시기 바라며……</color>","JPN":"<color=#ffd34c>事務員の方は非常通路から待避して……</color>","ENG":"<color=#ffd34c>All employees, please evacuate to the emergency exits...</color>","TWN":"<color=#ffd34c>請員工儘速利用緊急通道離開……</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"제길, 독 안에 든 쥐가 따로없군.","JPN":"くそ、袋のネズミ状態だな。","ENG":"Crap... We're like fish in a barrel.","TWN":"該死，我們現在根本是甕中之鱉。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"레비아, 아직이냐?","JPN":"レヴィア、まだなのか？","ENG":"Any time now, Levia!","TWN":"莉維亞，還沒好嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에헷. 방금 메시지로 루트 찍어서 보냈어요. 편안히 오시라고 길 닦아 두느라.","JPN":"えへっ。今メッセージでルート送りましたよ。楽に来れるように道を掃除してたんで。","ENG":"Hehe. Just messaged you the exit route. Took some time because I was cleaning up the place.","TWN":"嘿嘿，剛剛已經拍下路徑發訊息過去啦，還順便幫你清理掉路障，讓你來的路上可以輕鬆一點。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"좋아. 위에서 보자.","JPN":"了解。上で会おう。","ENG":"All right. I'll see you up top.","TWN":"很好，上面見。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장, 레비아에게 들었어. 자기 동생 얘기.","JPN":"隊長、レヴィアから聞いた。あいつの妹の話。","ENG":"Captain. Levia told me about her younger sister.","TWN":"隊長，我有聽莉維亞說關於她妹妹的事。"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"참 빨리도 들었군. 다음에 들어올 녀석은 외동이었으면 좋겠어.","JPN":"そりゃ、早かったな。次に入ってくるやつは一人っ子であってほしいもんだ。","ENG":"Took you long enough. I just wish our next recruit was an only child.","TWN":"這麼快就聽說啦？希望下次進來的是獨生子。"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"설마 지훈이 때문에 그렇게 쉽게 받아들였던 거야?","JPN":"まさか、ゴトウの件があったから簡単に受け入れたのか？","ENG":"Wait, did you take her in just because of Jihoon?","TWN":"你是因為智勳的關係，才這麼輕易讓她進來嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"부탁이니까 너희 둘의 짠한 우정에 나까지 끌어들이지 마라.","JPN":"頼むからお前たちの悲しい友情に俺まで巻き込むな。","ENG":"Please, don't drag me into a touching romance of you two, okay?","TWN":"拜託一下，不要把我扯進你們灑狗血的友情裡。"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"같이 일할 민병대원의 씨가 마르고 있어. 이 짓을 계속하려면 있는 건 모두 써먹어야 돼.","JPN":"民兵隊の数が少なすぎるんだ。この仕事を続けるために使えるものは全部使う。","ENG":"We're running out of members who want to join the Militia. If we want to keep this up, we'll have to use anyone we can get.","TWN":"可以一起拼命的民兵隊人數正在萎縮，要想繼續幹下去，就必須借助各種能力。"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이유리 네 힘처럼. 그것뿐이다.","JPN":"カスカベ、お前の力みたいに。それだけだ。","ENG":"Like you and your abilities, Yuri. That's all.","TWN":"李悠麗，就像你的力量，如此而已。"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"레비아는 아직이군. 우리가 좀 빨리 온 건가.","JPN":"レヴィアはまだだな。俺たちが少し早かったか？","ENG":"Levia's not here yet. I guess we got here a little early.","TWN":"莉維亞還沒到，是我們動作太快嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"응? 저 여자는……?","JPN":"うん？　あの女は……？","ENG":"Hmm? Isn't she...?","TWN":"嗯？那女的是……？"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"너무 늦지 않아서 다행이네요. ","JPN":"手遅れではなかったようですね。 ","ENG":"Thank goodness I wasn't late. ","TWN":"幸好還來得及。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"옷차림을 봐서는 경찰에 수배된 민병대 분들 같은데, 제가 잘못 짚은 건 아니겠죠?","JPN":"格好から見ると警察に指名手配されている民兵隊の方々のようですけど、私の見間違いでしょうか？","ENG":"From the looks of it, you're the Militia? The wanted fugitives, if I'm not mistaken?","TWN":"看你們的穿著，應該是警方正在通緝的民兵隊吧？我沒猜錯吧？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그러는 그쪽도 이런 회사에 어울리는 옷차림은 아니군. 태스크포스인가?","JPN":"そういうそちらもこんな会社にいるような格好ではないな。タスクフォースか？","ENG":"You don't look like you're part of the company. What are you? TASKFORCE?","TWN":"我看你的穿著也跟這間公司不太搭，你是特遣勢力嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네. 알파트릭스 이노베이션의 이진입니다.","JPN":"はい。アルファトリックス・イノベーションのシノザキ・ホノカと申します。","ENG":"Correct. I am Lee Jin of Alphatrix Innovation.","TWN":"是的，我是阿爾法崔克斯改革的李珍。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"잠시 시간 좀 내 주셔야겠어요. 여러분과 할 얘기가 많거든요.","JPN":"少々お時間よろしいでしょうか？　みなさんにお話したいことがあります。","ENG":"If I could borrow some of your time, please. There is a lot I have to discuss with you all.","TWN":"可能要佔用各位一些時間，我有很多話要跟你們說。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};